from flask import Flask, request, jsonify
from flask import g
import jwt
import requests
from functools import wraps

app = Flask(__name__)

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')
        
        if not token:
            return jsonify({'message': 'Token is missing'}), 401
        
        try:
            # Extract token from "Bearer <token>" format
            token = token.split(' ')[1]
            # Decode token without verification for development
            decoded_token = jwt.decode(token, algorithms=['HS256'], options={"verify_signature": False})
            g.user_claims = decoded_token
        except Exception as e:
            return jsonify({'message': 'Token is invalid'}), 401
            
        return f(*args, **kwargs)
    return decorated

@app.before_request
def before_request():
    pass

@app.route('/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
@token_required
def proxy(path):
    # Forward request to backend service with user claims
    backend_url = f"http://backend-service/{path}"
    
    # Prepare headers for backend
    headers = {}
    for key, value in request.headers:
        if key.lower() not in ['authorization', 'host']:
            headers[key] = value
    
    # Add user claims to headers
    headers['X-User-Claims'] = str(g.user_claims)
    
    # Forward request to backend
    try:
        if request.method == 'GET':
            response = requests.get(backend_url, headers=headers, params=request.args)
        elif request.method == 'POST':
            response = requests.post(backend_url, headers=headers, json=request.get_json())
        elif request.method == 'PUT':
            response = requests.put(backend_url, headers=headers, json=request.get_json())
        elif request.method == 'DELETE':
            response = requests.delete(backend_url, headers=headers)
        
        return jsonify(response.json()), response.status_code
    except Exception as e:
        return jsonify({'message': 'Backend service error'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)